  1→/**
  2→ * ContractRepository - CRUD operations for Contract model
  3→ *
  4→ * Provides typed methods for Contract queries with soft-delete support.
  5→ * Handles contract versions and signers.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Contract,
 11→  ContractVersion,
 12→  ContractSigner,
 13→  Prisma,
 14→  Deal,
 15→} from '@prisma/client';
 16→import { randomUUID } from 'node:crypto';
 17→
 18→/**
 19→ * Contract creation input type
 20→ */
 21→export type ContractCreateInput = Omit<Prisma.ContractUncheckedCreateInput, 'id' | 'number' | 'createdAt' | 'updatedAt'>;
 22→
 23→/**
 24→ * Contract update input type
 25→ */
 26→export type ContractUpdateInput = Prisma.ContractUncheckedUpdateInput;
 27→
 28→/**
 29→ * Contract findMany params type
 30→ */
 31→export type ContractFindManyParams = {
 32→  where?: Prisma.ContractWhereInput;
 33→  orderBy?: Prisma.ContractOrderByWithRelationInput;
 34→  skip?: number;
 35→  take?: number;
 36→  include?: Prisma.ContractInclude;
 37→};
 38→
 39→/**
 40→ * Repository for Contract CRUD operations
 41→ */
 42→export class ContractRepository {
 43→  /**
 44→   * Generate contract number in format Д-YYYY-NNNNN
 45→   */
 46→  private generateNumber(): string {
 47→    const year = new Date().getFullYear();
 48→    const random = Math.floor(Math.random() * 99999).toString().padStart(5, '0');
 49→    return `Д-${year}-${random}`;
 50→  }
 51→
 52→  /**
 53→   * Find many contracts with optional filtering
 54→   * Automatically filters out soft-deleted records
 55→   */
 56→  async findMany(params?: ContractFindManyParams): Promise<Contract[]> {
 57→    const { where, ...rest } = params ?? {};
 58→
 59→    return prisma.contract.findMany({
 60→      ...rest,
 61→      where: {
 62→        ...where,
 63→        deletedAt: null, // Always exclude soft-deleted
 64→      },
 65→    });
 66→  }
 67→
 68→  /**
 69→   * Find a single contract by ID
 70→   * Returns null if not found or soft-deleted
 71→   */
 72→  async findUnique(
 73→    id: string,
 74→    include?: Prisma.ContractInclude
 75→  ): Promise<Contract | null> {
 76→    return prisma.contract.findFirst({
 77→      where: { id, deletedAt: null },
 78→      include,
 79→    });
 80→  }
 81→
 82→  /**
 83→   * Find contracts by contact
 84→   */
 85→  async findByContact(contactId: string): Promise<Contract[]> {
 86→    return this.findMany({
 87→      where: { contactId },
 88→      orderBy: { createdAt: 'desc' },
 89→    });
 90→  }
 91→
 92→  /**
 93→   * Find contract by deal ID
 94→   */
 95→  async findByDeal(dealId: string): Promise<Contract | null> {
 96→    return prisma.contract.findFirst({
 97→      where: { dealId, deletedAt: null },
 98→    });
 99→  }
100→
101→  /**
102→   * Create a new contract
103→   * Generates UUID, number, and timestamps if not provided
104→   */
105→  async create(data: ContractCreateInput): Promise<Contract> {
106→    const now = new Date();
107→
108→    return prisma.contract.create({
109→      data: {
110→        ...data,
111→        id: data.id ?? randomUUID(),
112→        number: data.number ?? this.generateNumber(),
113→        createdAt: data.createdAt ?? now,
114→        updatedAt: data.updatedAt ?? now,
115→      },
116→    });
117→  }
118→
119→  /**
120→   * Update an existing contract
121→   * Throws RecordNotFound if contract doesn't exist or is soft-deleted
122→   */
123→  async update(
124→    id: string,
125→    data: ContractUpdateInput
126→  ): Promise<Contract> {
127→    // Verify contract exists and not deleted
128→    const existing = await this.findUnique(id);
129→    if (!existing) {
130→      throw new Error(`Contract with id ${id} not found`);
131→    }
132→
133→    return prisma.contract.update({
134→      where: { id },
135→      data: {
136→        ...data,
137→        updatedAt: new Date(),
138→      },
139→    });
140→  }
141→
142→  /**
143→   * Soft delete a contract by setting deletedAt timestamp
144→   */
145→  async softDelete(id: string): Promise<Contract> {
146→    const existing = await this.findUnique(id);
147→    if (!existing) {
148→      throw new Error(`Contract with id ${id} not found`);
149→    }
150→
151→    return prisma.contract.update({
152→      where: { id },
153→      data: { deletedAt: new Date() },
154→    });
155→  }
156→
157→  /**
158→   * Count contracts matching criteria (excluding soft-deleted)
159→   */
160→  async count(where?: Prisma.ContractWhereInput): Promise<number> {
161→    return prisma.contract.count({
162→      where: {
163→        ...where,
164→        deletedAt: null,
165→      },
166→    });
167→  }
168→
169→  /**
170→   * Add a version to a contract
171→   */
172→  async addVersion(
173→    contractId: string,
174→    contentMd: string,
175→    createdBy: string,
176→    generatedPdfFileId?: string
177→  ): Promise<ContractVersion> {
178→    // Get next version number
179→    const latestVersion = await prisma.contractVersion.findFirst({
180→      where: { contractId },
181→      orderBy: { version: 'desc' },
182→    });
183→
184→    const nextVersion = (latestVersion?.version ?? 0) + 1;
185→
186→    return prisma.contractVersion.create({
187→      data: {
188→        id: randomUUID(),
189→        contractId,
190→        version: nextVersion,
191→        contentMd,
192→        generatedPdfFileId,
193→        createdBy,
194→        createdAt: new Date(),
195→      },
196→    });
197→  }
198→
199→  /**
200→   * Get all versions of a contract
201→   */
202→  async getVersions(contractId: string): Promise<ContractVersion[]> {
203→    return prisma.contractVersion.findMany({
204→      where: { contractId },
205→      orderBy: { version: 'desc' },
206→    });
207→  }
208→
209→  /**
210→   * Add a signer to a contract
211→   */
212→  async addSigner(
213→    contractId: string,
214→    name: string,
215→    position?: string,
216→    signatureFileId?: string
217→  ): Promise<ContractSigner> {
218→    return prisma.contractSigner.create({
219→      data: {
220→        id: randomUUID(),
221→        contractId,
222→        name,
223→        position,
224→        signatureFileId,
225→      },
226→    });
227→  }
228→
229→  /**
230→   * Get all signers of a contract
231→   */
232→  async getSigners(contractId: string): Promise<ContractSigner[]> {
233→    return prisma.contractSigner.findMany({
234→      where: { contractId },
235→      orderBy: { id: 'asc' },
236→    });
237→  }
238→
239→  /**
240→   * Convert a deal to a contract
241→   * Creates a contract from deal data and links them
242→   */
243→  async convertFromDeal(
244→    dealId: string,
245→    additionalData?: Partial<ContractCreateInput>
246→  ): Promise<Contract> {
247→    const deal = await prisma.deal.findFirst({
248→      where: { id: dealId, deletedAt: null },
249→      include: { contact: true },
250→    });
251→
252→    if (!deal) {
253→      throw new Error(`Deal with id ${dealId} not found`);
254→    }
255→
256→    // Check if contract already exists
257→    const existing = await this.findByDeal(dealId);
258→    if (existing) {
259→      throw new Error(`Contract already exists for deal ${dealId}`);
260→    }
261→
262→    // Create contract from deal
263→    const contract = await this.create({
264→      dealId,
265→      contactId: deal.contactId || undefined,
266→      title: `Договор: ${deal.title}`,
267→      amount: deal.amount,
268→      currency: deal.currency,
269→      description: deal.description || undefined,
270→      status: 'draft',
271→      ...additionalData,
272→    });
273→
274→    // Update deal with contractId
275→    await prisma.deal.update({
276→      where: { id: dealId },
277→      data: { contractId: contract.id },
278→    });
279→
280→    return contract;
281→  }
282→}
283→
284→/**
285→ * Singleton instance for use across the application
286→ */
287→export const contracts = new ContractRepository();
288→
289→export default contracts;
